INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('d3c49e4a-3259-42cb-a8ce-20254a096256', 'setup', 'wyckoff.risk.d.entry_sl_atr_mult', '"2.5"', 1, 'D-profile Wyckoff: SL = entry +/- N * ATR', false, '2026-04-14 16:04:39.889472+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('48a3719f-5e3c-4053-936c-2d25dc9e90c1', 'setup', 'wyckoff.risk.q.entry_sl_atr_mult', '"1.5"', 1, 'Q-profile Wyckoff: SL = entry +/- N * ATR', false, '2026-04-14 16:04:39.889472+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('490f8de7-3811-4e0e-a02c-8fc4daae2599', 'setup', 'wyckoff.backtest.from_iso', '"2023-01-01T00:00:00Z"', 1, 'Default backtest start (overridable per run)', false, '2026-04-14 16:04:39.889472+03', NULL);
