INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('0bc4db72-0c16-4744-8d1a-8cd2095b9eb8', 'setup', 'wyckoff.backtest.slippage_bps', '"5"', 1, 'Backtest entry/exit slippage in basis points', false, '2026-04-14 16:04:39.889472+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('336feb27-e76b-4880-8906-01b196adb189', 'setup', 'wyckoff.atr.period', '"14"', 1, 'ATR period for volatility bucketing and SL distance', false, '2026-04-14 16:04:39.889472+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('3915dbf4-3b2b-4c7c-8d37-03809b812f4b', 'setup', 'wyckoff.classic.cause_effect_factor', '"1.0"', 1, 'Multiplier on range_height for classical P&F target (Wyckoff Cause/Effect). 1.0 = full range projection.', false, '2026-04-14 16:06:00.393796+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('ba424410-ecd1-42a2-820b-faf439cfd2c6', 'setup', 'wyckoff.classic.spring_buffer_atr', '"0.5"', 1, 'SL buffer below Spring low in ATR units (classical Wyckoff)', false, '2026-04-14 16:06:00.393796+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('ecb23a91-b47c-49b7-b7ae-701229b4f3f6', 'setup', 'wyckoff.classic.lps_buffer_atr', '"0.3"', 1, 'SL buffer below LPS low in ATR units', false, '2026-04-14 16:06:00.393796+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('283c62f7-0821-42f9-ba8a-b894e44dee64', 'setup', 'wyckoff.classic.ut_buffer_atr', '"0.5"', 1, 'SL buffer above UT/UTAD high in ATR units', false, '2026-04-14 16:06:00.393796+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('12563a29-cc4c-412a-b3ab-487cd861e809', 'setup', 'wyckoff.classic.lpsy_buffer_atr', '"0.3"', 1, 'SL buffer above LPSY high in ATR units', false, '2026-04-14 16:06:00.393796+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('b564741c-0d01-4fa3-bd4d-e75c65e7055d', 'setup', 'wyckoff.classic.buec_buffer_atr', '"0.4"', 1, 'SL buffer below creek for BUEC retest', false, '2026-04-14 16:06:00.393796+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('32096fdb-8980-4d9c-bde7-655f9fca09ee', 'setup', 'wyckoff.classic.ice_retest_buffer_atr', '"0.4"', 1, 'SL buffer above ice for ice retest', false, '2026-04-14 16:06:00.393796+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('a02aa7fc-1e32-4cd9-9dc4-296c30f9377e', 'setup', 'wyckoff.sl.policy', '"tighter"', 1, 'How to combine classical and adaptive SL. tighter = min distance from entry (lower risk).', false, '2026-04-14 16:06:00.393796+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('afa45c58-9d8e-4097-a1d5-6d160765afe7', 'zigzag', 'slot_3', '{"color": "#f59e0b", "length": 13}', 1, 'Z4', false, '2026-04-21 20:53:21.379165+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('e1aacd18-6dfe-40e3-8e78-3acf10373efc', 'setup', 'wyckoff.tp.classical_cap_enabled', '"true"', 1, 'When true, no adaptive TP can exceed classical P&F target * range_cap_factor', false, '2026-04-14 16:06:00.393796+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('175fbd0c-924f-4427-aa03-0b11da39242a', 'setup', 'wyckoff.tracker.enabled', '"true"', 1, 'Master switch for the Wyckoff status tracker loop.', false, '2026-04-14 19:47:54.192072+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('344244be-10f2-4eaa-8c45-a479b0ae5d34', 'setup', 'wyckoff.tracker.interval_seconds', '"15"', 1, 'Tick interval for the Wyckoff status tracker (seconds).', false, '2026-04-14 19:47:54.192072+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('8bde93b2-f056-4709-979b-ce1535b58a23', 'setup', 'wyckoff.tracker.lookback_bars', '"200"', 1, 'How many recent bars the tracker fetches when no cursor exists.', false, '2026-04-14 19:47:54.192072+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('4623e9e1-2657-4d1b-9ffd-780767957ef2', 'setup', 'wyckoff.tracker.entry_touch_bps', '"5"', 1, 'Slack (basis points) around entry_price counted as a touch. 5 = 0.05%.', false, '2026-04-14 19:47:54.192072+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('17afbeee-9a92-4b9c-82ae-ba1d6d034efa', 'setup', 'wyckoff.tp.min_net_rr', '"1.5"', 1, 'Reject setup if weighted expected net R < N (Pruden/Weis floor = 1.5).', false, '2026-04-14 16:18:54.243413+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('527517d2-dfd8-4bc7-a90d-6050ba8ef959', 'setup', 'wyckoff.tp.range_cap_factor', '"2.0"', 1, 'TP price cannot exceed breakout ± range_height × factor. 2.0 = canonical TP3 extended measured move.', false, '2026-04-14 16:04:39.889472+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('9934017f-ae3c-414e-9537-9829c7f1a832', 'detector', 'wyckoff.max_range_height_pct', '"0.15"', 1, 'Reject ranges whose height / midpoint exceeds this fraction. Base default 0.15; set 0.08 on H1, 0.30 on D1.', false, '2026-04-14 21:37:28.301328+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('467851ef-8a4e-48fd-88fe-db8fe0419504', 'detector', 'wyckoff.max_range_age_bars', '"500"', 1, 'Reject ranges whose pivot span exceeds N bars. Stale range guard.', false, '2026-04-14 21:37:28.301328+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('7ca9b44f-d967-4626-ad63-5f30689f9cd5', 'detector', 'wyckoff.spring_no_supply_vol_ratio', '"0.8"', 1, 'Spring bar volume <= N × avg_vol → #3 No-Supply (strongest variant, score +25%).', false, '2026-04-14 21:37:28.301328+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('a29597cb-4bf2-48c2-bc7d-483270b07c2d', 'detector', 'wyckoff.spring_terminal_vol_ratio', '"3.0"', 1, 'Spring bar volume >= N × avg_vol → #1 Terminal (weakest variant, score -30%).', false, '2026-04-14 21:37:28.301328+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('6a59ad47-a0f3-4908-9359-d53663e3f21b', 'detector', 'wyckoff.skip_terminal_springs', '"true"', 1, 'Skip #1 Terminal Springs entirely. Default true per Pruden: they are aggressive and low edge.', false, '2026-04-14 21:37:28.301328+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('e217fe31-d096-41aa-b215-2b759a5fd544', 'detector', 'wyckoff.max_range_volume_expansion', '"1.3"', 1, 'Reject ranges where late-half pivot volume / early-half > N. Wyckoff ranges contract volume; expansion = trending market, not accumulation.', false, '2026-04-14 21:37:28.310451+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('2cd5e7df-429c-4f8b-8347-7fa4a7a42417', 'worker', 'pivot_backfill_enabled', '{"enabled": true}', 1, 'Enable the pivot historical backfill worker. Backfills L0..L3 pivots from the first stored bar so detectors and backtests see full history.', false, '2026-04-14 21:37:28.315797+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('426f5006-dc3a-43ce-a81e-18bd890f9de1', 'worker', 'pivot_backfill_tick_secs', '3600', 1, 'Poll interval for the pivot historical backfill worker. Hourly is enough — the work is idempotent and only runs when new bars accumulate past the per-series cursor.', false, '2026-04-14 21:37:28.315797+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('c8423268-7131-4b7e-9349-77e8f8898ee1', 'detector', 'pivot_backfill.chunk_bars', '5000', 1, 'Chunk size when paging through market_bars during backfill. Larger = fewer round-trips, more memory per symbol.', false, '2026-04-14 21:37:28.315797+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('026764bc-740b-4413-86aa-0a515f8d5213', 'detector', 'pivot_backfill.min_bars', '60', 1, 'Skip series with fewer than N bars — not enough to produce meaningful pivots.', false, '2026-04-14 21:37:28.315797+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('f00a54b9-a48a-46da-ab7f-57d465f2db69', 'detection', 'historical_progressive_scan.stride_bars', '50', 1, 'Step size in bars between detection invocations during replay. Smaller = denser coverage but more detector calls; larger = faster but risks skipping transient patterns.', false, '2026-04-14 21:52:50.66467+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('96640e65-b822-4348-a496-277b803a7f28', 'detection', 'historical_progressive_scan.min_offset_bars', '100', 1, 'Minimum starting offset (in bars). Detectors need enough warm-up history — firing at offset 0 would only produce noise.', false, '2026-04-14 21:52:50.66467+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('70e2cccb-bd8a-49d4-ab8d-85659c8de411', 'detection', 'historical_progressive_scan.max_offsets_per_pass', '200', 1, 'Upper bound on detector invocations per symbol per worker tick. Keeps any single pass bounded while the full series gets chipped through across many hours.', false, '2026-04-14 21:52:50.66467+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('46f6c054-9ea0-4f99-a0ad-c781014c671c', 'detection', 'elliott.pivot_levels', '"L0,L1,L2,L3"', 1, 'Elliott detector çalışacağı pivot seviyeleri. Virgülle ayrılmış: "L0,L1" ya da "L0,L1,L2,L3". Her seviye bağımsız runner oluşturur.', false, '2026-04-20 21:14:36.442267+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('dd605d0a-1cbb-4629-943f-da22ce08d6d7', 'detection', 'historical_progressive_scan.tick_secs', '300', 1, 'Poll interval for the progressive scan loop. Hourly is enough — work is idempotent, resumes from cursor, caps per symbol via max_offsets_per_pass.', false, '2026-04-14 21:52:50.66467+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('981a1025-ff9c-4d15-9fea-f93842b2b559', 'setup', 'wyckoff.htf_gate.enabled', 'true', 1, 'Enable the multi-timeframe Wyckoff phase-harmony gate. When true, LTF setups whose direction conflicts with the HTF structures committed bias (phase >= C) are dropped before persistence.', false, '2026-04-14 22:23:05.286105+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('a2a73f61-fcd6-40f4-98cb-45438d3c560a', 'setup', 'wyckoff.htf_gate.mapping', '{"1d": "1w", "1h": "4h", "4h": "1d", "15m": "1h"}', 1, 'LTF → HTF mapping consulted by the phase-harmony gate. JSON object; unmapped timeframes bypass the gate.', false, '2026-04-14 22:23:05.286105+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('6e4f69b3-a612-4f6d-bcc5-8a13b94df17d', 'detector', 'wyckoff.manipulation_max_edge_slope', '"0.004"', 1, 'P20 — reject Spring/UTAD when same-kind pivot slope exceeds this fraction-per-pivot (0.004 = 0.4%/pivot). Kills false positives in trending markets.', false, '2026-04-15 02:37:58.415677+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('a1d4e9eb-18ab-4916-a70d-2ccd30550d7e', 'tbm', 'setup.max_anchor_age_bars', '"12"', 1, 'P22 — forming TBM detection auto-invalidated after this many bars since anchor. Bar count applies on the same TF: 12h on H1, ~2 days on 4h, 12 days on 1d.', false, '2026-04-15 02:53:40.44883+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('a15e3624-e6df-4b4f-99f5-5432502a9d94', 'tbm', 'anchor.pivot_radius', '"3"', 1, 'P22f — bars on each side a candidate must dominate to count as a pivot extreme. 3 = standard fractal; raise to 5 for slower pivots on 1d+.', false, '2026-04-15 04:06:27.347137+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('58900561-5195-4da8-ad3b-9bbcc7ed4e55', 'tbm', 'anchor.min_right_bars', '"3"', 1, 'P22f — minimum completed bars AFTER a candidate before it is eligible as an anchor. Keeps the picker off the currently forming bar. 3 bars = typical Wyckoff right-side confirmation window.', false, '2026-04-15 04:06:27.347137+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('d09a0d74-eb85-46e7-8747-5dd88e4d2c76', 'tbm', 'anchor.wick_min_ratio', '"0.25"', 1, 'P22f — candidate must have lower/upper wick ≥ 25% of its total range. Eliminates mid-trend bars without a rejection tail. Raise toward 0.4 for cleaner sweeps, lower toward 0.15 for noisier markets.', false, '2026-04-15 04:06:27.347137+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('71d815bd-f857-4fa5-b6de-4c25b9910317', 'tbm', 'anchor.vol_min_ratio', '"1.0"', 1, 'P22f — bar volume baseline vs 20-bar average for climax bonus. Below this ratio contributes 0; above, contributes linearly up to +1. 1.0 = neutral (average).', false, '2026-04-15 04:06:27.347137+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('5e9f85c8-a957-4234-8299-e4eea048402b', 'tbm', 'confirm.bos_required', '"1"', 1, 'P23 — master flag for BoS-gated confirmation. 1 = require break-of-structure + follow-through before a TBM setup graduates from forming to confirmed; 0 = legacy validator-only path.', false, '2026-04-15 04:06:27.363204+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('b565b01c-1cd1-43e7-9b6c-11b25efcda5b', 'tbm', 'confirm.window_bars', '"8"', 1, 'P23 — bars to wait after the anchor for a BoS close to print. Expired without BoS → invalidated(timeout). 8 bars ≈ 8h on H1, ~1.3 days on 4h.', false, '2026-04-15 04:06:27.363204+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('d089d171-4269-4053-be4f-50d0429ef935', 'zigzag', 'slot_4', '{"color": "#a78bfa", "length": 21}', 1, 'Z5 — longest zigzag (structural)', false, '2026-04-21 20:53:21.379165+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('dd7a34b4-901e-4bac-ab60-c2f84a765b1d', 'gap', 'enabled', '{"enabled": true}', 1, 'Master on/off for the gap-and-island-reversal engine writer.', false, '2026-04-23 22:43:57.36467+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('e61ba8c9-2aef-4fb7-a250-a4e21437134e', 'tbm', 'confirm.followthrough_atr_mult', '"1.0"', 1, 'P23 — follow-through closing move measured in ATR(14) units above (bottom) / below (top) the anchor. 1.0 = one ATR; raise for stricter confirmation, lower for noisy markets.', false, '2026-04-15 04:06:27.363204+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('22f847f4-0787-4b70-aae9-2b1818b5fbb9', 'tbm', 'confirm.followthrough_bars', '"3"', 1, 'P23 — bars after the BoS bar within which the follow-through close must appear. 3 is a reasonable default for most TFs.', false, '2026-04-15 04:06:27.363204+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('58bc44e7-999f-46e1-b647-92a6bc392fbb', 'tbm', 'anchor.sweep_required', '"0"', 1, 'P22f — when 1, a candidate anchor MUST take out a prior window extreme (liquidity sweep / fake breakdown / breakout) to qualify. 0 = sweep contributes as a weighted bonus only, so V-bottom reversals without a sweep still anchor. Toggle to 1 for pure-Wyckoff mode.', false, '2026-04-15 04:06:27.363204+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('c511a9cc-4799-4b47-9d02-e5032f52973f', 'detector', 'wyckoff.sos_min_bar_width_atr_mult', '1.5', 1, 'SOS/SOW wide-range gate (ATR proxy multiplier).', false, '2026-04-15 22:28:00.609735+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('ff65f1ec-424a-489b-9a33-c158f6ba2959', 'detector', 'wyckoff.sos_close_third_threshold', '0.66', 1, 'SOS/SOW close-in-third gate (upper/lower fraction).', false, '2026-04-15 22:28:00.609735+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('91777e2f-128e-4477-88da-8ebd7de6018c', 'detector', 'wyckoff.phase_b_min_bars', '10', 1, 'Minimum bars in Phase B before C may open.', false, '2026-04-15 22:28:00.609735+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('d87f4e7a-2fe7-43f7-a86d-4f9d5606b07f', 'detector', 'wyckoff.phase_b_min_inner_tests', '1', 1, 'Minimum Phase-B inner tests (UA/STB/ST) before C.', false, '2026-04-15 22:28:00.609735+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('ed20356c-4bb4-4588-b536-f99ad21fe0c3', 'detector', 'wyckoff.spring_test_max_vol_ratio', '0.6', 1, 'Spring/UTAD Test volume fraction of parent Spring/UTAD.', false, '2026-04-15 22:28:00.609735+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('ea389334-adf3-4b3f-9314-2a93bb3a6549', 'tbm', 'confirm.retest_max_age_bars', '"12"', 1, 'P23c — maximum bars after the BoS bar within which a retest is still accepted. Past this point we assume the trend moved on without a textbook retest. 12 is reasonable for most TFs; shorten on LTF scalping setups.', false, '2026-04-15 04:06:27.371308+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('930ab661-ed6a-4b75-9f2b-2dd107f0013b', 'tbm', 'confirm.retest_proximity_atr', '"0.5"', 1, 'P23c — how close (in ATR(14) multiples) the pullback wick must come to the broken structural level to count as a real retest. 0.5 = within half an ATR. Raise for more forgiving retests, lower for strict "touch" requirements.', false, '2026-04-15 04:06:27.371308+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('d06a4521-2e13-4c99-8e7a-d8d40c397224', 'tbm', 'anchor.equal_level_tol', '"0.002"', 1, 'P22g — tolerance (fraction of price) within which a prior pivot counts as an equal-level touch. 0.002 = 0.2%. Tighten for cleaner double/triple bottoms/tops, loosen for wider liquidity pools.', false, '2026-04-15 04:06:27.378013+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('8f3dc6db-cd1b-41bc-9f41-58f14bf6bd29', 'tbm', 'anchor.equal_level_min_touches', '"1"', 1, 'P22g — minimum number of prior pivot touches (NOT counting the candidate itself) at roughly the candidate''s price for the equal-level bonus to fire. 1 = classic double bottom/top, 2 = triple.', false, '2026-04-15 04:06:27.378013+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('c4692254-0fd3-4395-9845-2a545914a9e3', 'tbm', 'anchor.equal_level_required', '"0"', 1, 'P22g — when 1, a candidate without the required equal-level touches is rejected outright (pure liquidity-pool mode). 0 = bonus only.', false, '2026-04-15 04:06:27.378013+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('9bc9d8cb-188a-4d01-8cdf-142b70bc8704', 'tbm', 'checklist.min_tier', '"ok"', 1, 'P23d — minimum tier a TBM setup must reach before default GUI/alert surfaces pick it up. Ladder: elite(5) > strong(4) > ok(3) > weak(2) > filtered(≤1). Set to "weak" to see early forming setups, "strong" to only surface high-conviction reversals.', false, '2026-04-15 04:18:44.224635+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('de265e42-0959-4525-9347-15b1780e0b18', 'tbm', 'checklist.min_score', '"3"', 1, 'P23d — numeric floor on the reversal checklist score (0–5). Used alongside checklist.min_tier; the stricter of the two wins. 3 = "at least 3 of 5 textbook legs present".', false, '2026-04-15 04:18:44.224635+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('7b4d6870-f423-45ac-9f23-a4956ef9ae54', 'tbm', 'effort_result.enabled', '"1"', 1, 'P24 — master switch for the Wyckoff effort-vs-result detector. 1=on (adds volume-pillar bonus on no-supply/no-demand/absorption bars), 0=off.', false, '2026-04-15 04:18:44.233828+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('f04f7347-1fcd-49eb-959d-97dfeeb8c5b8', 'tbm', 'effort_result.scan_bars', '"8"', 1, 'P24 — trailing bars (ending at the anchor) scanned for effort-vs-result tells. 8 is a sensible window; raise to pick up older exhaustion bars, lower for pure anchor-vicinity scoring.', false, '2026-04-15 04:18:44.233828+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('3b667d38-8fed-4734-8a80-1ab5145d7063', 'tbm', 'effort_result.range_small_ratio', '"0.7"', 1, 'P24 — a bar''s total range must be ≤ this × 20-bar avg range to count as "small" (narrow-range bar, classic Wyckoff absorption/no-demand tell).', false, '2026-04-15 04:18:44.233828+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('f053a43a-ef1c-40e5-b2f4-a50487bc0072', 'tbm', 'effort_result.vol_low_ratio', '"0.8"', 1, 'P24 — volume gate for no-supply/no-demand: bar volume ≤ this × 20-bar avg. Lower = stricter (only truly dry-volume bars count).', false, '2026-04-15 04:18:44.233828+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('b658ecf2-d4a1-4946-89b9-2a9f9441d049', 'tbm', 'effort_result.vol_high_ratio', '"1.5"', 1, 'P24 — volume gate for absorption: bar volume ≥ this × 20-bar avg. Higher = stricter (only real effort bars count).', false, '2026-04-15 04:18:44.233828+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('fa00c735-2854-4be7-b6cb-3e3effd1ff76', 'tbm', 'effort_result.no_supply_demand_pts', '"10"', 1, 'P24 — points awarded per no-supply / no-demand bar found in the scan window.', false, '2026-04-15 04:18:44.233828+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('4758244f-7be5-48f9-a8d4-eeb72d2fb4e9', 'tbm', 'effort_result.absorption_pts', '"15"', 1, 'P24 — points awarded per absorption bar found in the scan window (effort-without-result is the strongest single tell).', false, '2026-04-15 04:18:44.233828+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('d4c2cad5-f251-4309-9ba6-7bb94c777df7', 'tbm', 'effort_result.max_bonus_pts', '"25"', 1, 'P24 — total cap on the effort-vs-result bonus (keeps stacked signals from blowing the volume pillar out).', false, '2026-04-15 04:18:44.233828+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('2ad8708e-8d26-49fe-93b8-08ba87944b3d', 'tbm', 'mtf.htf_parents', '"1m:5m,5m:15m,15m:1h,1h:4h,4h:1d,1d:1w"', 1, 'P26 — parent-TF ladder for HTF confluence lookup, CSV pairs "ltf:htf". When a setup fires on the LTF, the detector queries the mapped HTF for an active (forming/confirmed) same-direction TBM row. Missing entries disable confluence for that TF.', false, '2026-04-15 04:29:00.536278+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('185ad06b-0bae-476e-b3af-d4c5fe15d353', 'onchain', 'aggregator.ltf_cadence_s', '3600', 1, 'Max reading cadence (s) that contributes to the ltf onchain aggregate.', false, '2026-04-15 19:44:33.226663+03', NULL);
