INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('ab5e4fe8-2806-49db-802d-fb4f769b2098', 'backtest', 'setup_loop.min_structural_score', '0.60', 1, 'Floor on detection.structural_score before arming. Backtest bypasses live confluence gate so structural_score is the only shape-quality filter.', false, '2026-04-19 16:17:24.790984+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('a0d40830-00ee-4ae0-ba25-52e7ffbd55d0', 'backtest', 'setup_loop.atr_period', '14', 1, 'ATR window (bars) for point-in-time stop sizing when structural invalidation is unusable.', false, '2026-04-19 16:17:24.790984+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('20ad379c-620c-4ebd-8a8f-5133c9cfe923', 'backtest', 'setup_loop.atr_lookback_bars', '30', 1, 'How many bars before detection.detected_at to fetch for ATR computation.', false, '2026-04-19 16:17:24.790984+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('e213d2f2-4bde-48c6-a4b7-e645a5b3cbce', 'backtest', 'setup_loop.entry_sl_atr_mult', '1.0', 1, 'ATR-fallback SL distance multiplier when detection invalidation_price is missing or on the wrong side of entry.', false, '2026-04-19 16:17:24.790984+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('04d3491d-5a8c-402b-bf42-a14c19c16f20', 'backtest', 'setup_loop.target_ref_r', '2.0', 1, 'ATR-fallback target in R multiples (distance from entry to initial SL).', false, '2026-04-19 16:17:24.790984+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('ae931ac3-d078-4eec-a655-c42951348c5e', 'gap', 'bars_per_tick', '{"bars": 2000}', 1, 'Upper bound on recent bars loaded per symbol per tick.', false, '2026-04-23 22:43:57.36467+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('a65a7b79-ba82-4d3e-8fa5-f1ffc2789886', 'backtest', 'setup_loop.risk_pct', '0.5', 1, 'Per-trade risk percent stamped on the backtest setup (used by portfolio sizing downstream).', false, '2026-04-19 16:17:24.790984+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('def8c672-d924-4451-90b8-e279d5d5802d', 'backtest', 'setup_loop.skip_if_live_setup_open', 'true', 1, 'Safety: skip arming a backtest setup when a live/dry setup for the same (ex,sym,tf,profile) is already open. Prevents historical replay from colliding with an in-flight live trade during concurrent dev runs.', false, '2026-04-19 16:17:24.790984+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('fcc2fd75-e9eb-4a0e-857b-ef5462a2a0a9', 'detection', 'classical.scallop_score_w_curvature', '0.35', 1, 'Scallop confidence: parabolic R² (curvature) weight. Bulkowski J-shape requires a tight curve; this dominates the score. Calibration target: sweep 0.25..0.50 against /v2/backtest/summary?alt_type_like=scallop_%.', false, '2026-04-19 16:41:33.117675+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('987130d7-6c1e-4a12-962b-932dc75b03b5', 'detection', 'classical.scallop_score_w_progress', '0.25', 1, 'Scallop confidence: rim progression (asymmetry) weight. Bigger right rim = stronger directional intent.', false, '2026-04-19 16:41:33.117675+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('c59a2430-09ef-4ab9-900d-e969e50f46c3', 'detection', 'classical.scallop_score_w_breakout', '0.25', 1, 'Scallop confidence: breakout magnitude (close vs RimR ± ATR) weight. Gates false pivots that never follow through.', false, '2026-04-19 16:41:33.117675+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('945bcd09-0c44-4de5-aa33-46746fec3810', 'detection', 'classical.scallop_score_w_volume', '0.15', 1, 'Scallop confidence: breakout bar volume (vs trailing avg) weight. Lowest because crypto volume data varies by venue.', false, '2026-04-19 16:41:33.117675+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('30e2c73c-2dd7-4588-af2b-404f8fc4dd0e', 'setup', 'wyckoff.plan.min_target_price_frac', '0.001', 1, 'TP/SL hard floor as fraction of entry price. Guards against R-multiple short ladders projecting sub-zero targets (bug_negative_target_price.md). Setups whose TP1 drops below this floor are rejected with NegativeTargetProjection.', false, '2026-04-19 17:15:34.394722+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('58b9ed02-b276-499c-af1e-39331dc91d06', 'setup', 'profile.t.min_target_price_frac', '0.001', 1, 'T (Trader) profile — TP/SL floor as fraction of entry. Guards PositionGuard ATR fallback against negative target_ref. See bug_negative_target_price.md.', false, '2026-04-19 18:15:01.343944+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('25e2811e-dcf8-4b7f-8477-02af2325a4b5', 'setup', 'profile.q.min_target_price_frac', '0.001', 1, 'Q (Quant) profile — TP/SL floor as fraction of entry.', false, '2026-04-19 18:15:01.343944+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('fb2e37a1-c91a-4823-8710-7e5863a47fc2', 'setup', 'profile.d.min_target_price_frac', '0.001', 1, 'D (Discretionary) profile — TP/SL floor as fraction of entry.', false, '2026-04-19 18:15:01.343944+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('e49019c0-f4f2-40aa-90b1-354d67abb914', 'elliott_corrective', 'flat_regular', '{"max_c": 1.15, "min_b": 0.90, "min_c": 0.85}', 1, 'Regular flat: B ~= 100%% of A, C ~= 100%% of A.', false, '2026-04-22 02:23:14.00275+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('a1a44830-9500-4f91-b893-8d898fb1eb66', 'elliott_corrective', 'triangle_barrier_flat_tol', '{"tol": 0.05}', 1, 'Fractional tolerance for a triangle trendline to count as "horizontal" (barrier type). 0.05 = 5%%.', false, '2026-04-22 02:23:14.00275+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('d08de4af-7899-446b-bbba-d40055c57326', 'elliott_corrective', 'enabled', '{"enabled": true}', 1, 'Toggle Flat + Triangle refinement in the Pine port. Set false to emit only plain ABC/zigzag.', false, '2026-04-22 02:23:14.00275+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('a88f61d8-fa1f-49dc-9856-149bf90140d9', 'detections', 'enabled', '{"enabled": true}', 1, 'Master switch for the detections writer loop. When true the worker mirrors /v2/elliott output into the detections table each tick.', false, '2026-04-22 21:06:53.945765+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('1e8b7209-e43d-485d-931f-5dac587ac6bf', 'detections', 'tick_secs', '{"secs": 60}', 1, 'Polling interval in seconds. 60 matches pivot_writer_loop cadence so detections settle one tick after their source pivots are written.', false, '2026-04-22 21:06:53.945765+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('9afe4f01-86bb-4eac-aa11-dfdf0a625537', 'detections', 'bars_per_tick', '{"bars": 2000}', 1, 'Recent-bar window fed to luxalgo_pine_port::run each tick. Larger = more history but slower. 2000 matches pivot_writer.', false, '2026-04-22 21:06:53.945765+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('9c8dcfa5-4e08-42cb-bc63-a0948aaa0985', 'harmonic', 'enabled', '{"enabled": true}', 1, 'Master switch for the harmonic_writer_loop. Active by default — user asked for harmonic patterns to land in detections table.', false, '2026-04-22 21:49:26.546066+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('2a327875-c2d9-4a54-8197-b52ad367ecdf', 'harmonic', 'tick_secs', '{"secs": 60}', 1, 'Polling cadence in seconds, matches the detections + pivot_writer loops.', false, '2026-04-22 21:49:26.546066+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('a3960e38-24e1-4ef9-9b08-c5b790469795', 'harmonic', 'min_score', '{"score": 0.60}', 1, 'Minimum structural score (Gaussian match quality, 0..1) for a harmonic to persist. 0.60 filters noisy near-misses while keeping solid matches.', false, '2026-04-22 21:49:26.546066+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('9e32f949-5e38-4444-8b7b-1d82f6cb949d', 'harmonic', 'slack', '{"slack": 0.05}', 1, 'Fractional loosening of every RatioRange (5 percent default). Matches the default in qtss_harmonic::HarmonicConfig.', false, '2026-04-22 21:49:26.546066+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('d7130a54-59ff-4ceb-8bdf-bf5fbfa7f95f', 'harmonic', 'pivots_per_slot', '{"count": 500}', 1, 'How many recent pivots per (series, slot) to scan each tick. 500 covers months on 4h / days on 5m at typical swing density.', false, '2026-04-22 21:49:26.546066+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('0cd537e4-9378-45a4-bf14-1fdd5732daa2', 'classical', 'enabled', '{"enabled": true}', 1, 'Master on/off for the classical chart-pattern engine writer. Gates the ClassicalWriter inside qtss-engine alongside the elliott/harmonic writers.', false, '2026-04-23 22:12:05.736098+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('90d246d6-ade5-4f38-bd5b-2585a708472d', 'classical', 'min_score', '{"score": 0.55}', 1, 'Minimum structural score (0..1) required before a classical match is persisted. Tighter (0.65+) = fewer but cleaner patterns; looser (0.45) = richer candidate pool for the validator to prune.', false, '2026-04-23 22:12:05.736098+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('3ca05cf7-dc9c-4daf-a1ac-76abee0425e7', 'classical', 'pivots_per_slot', '{"count": 500}', 1, 'Upper bound on recent pivots loaded per slot per tick. 500 covers roughly the last 6-24 hours on 1m-1h timeframes while keeping the sliding-window scan O(n*shapes) tractable.', false, '2026-04-23 22:12:05.736098+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('4fcc2bd0-167f-4ae1-a204-1d7dfe535b1a', 'classical', 'bars_per_tick', '{"bars": 2000}', 1, 'Upper bound on recent bars loaded per symbol per tick — used by the bar-aware shapes (flag, pennant, cup, rounding, scallop) that need ATR / flagpole context beyond pivots alone.', false, '2026-04-23 22:12:05.736098+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('232edef6-848d-429e-a61d-b4bbf166f452', 'classical', 'thresholds.equality_tolerance', '{"value": 0.03}', 1, 'Maximum relative deviation (0..0.25) between "equal" peaks or shoulders. 0.03 = ±3% tolerance. Looser for noisy low-TF, tighter for daily/weekly.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('9af02a3b-4426-480d-aab2-26688cdbd6d1', 'classical', 'thresholds.apex_horizon_bars', '{"value": 50}', 1, 'Triangle apex must fall within this many future bars of the last pivot — otherwise the pattern is too loose to be actionable.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('99ee33a7-e46c-47f8-9008-f28b0a5b51fb', 'gap', 'thresholds.min_gap_pct', '{"value": 0.005}', 1, 'Minimum gap magnitude as a fraction of close (0.005 = 0.5%).', false, '2026-04-23 22:43:57.36467+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('241d03ef-b70b-4736-ac7c-07cfa733d05a', 'gap', 'thresholds.volume_sma_bars', '{"value": 20}', 1, 'SMA window for volume baseline (volume-confirm ratio).', false, '2026-04-23 22:43:57.36467+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('a6b9454d-28c9-40de-9da1-e57d8b4c35ab', 'gap', 'thresholds.vol_mult_breakaway', '{"value": 1.5}', 1, 'Breakaway gap requires volume ≥ this × SMA.', false, '2026-04-23 22:43:57.36467+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('5905cdfb-ad57-4dc3-9b4f-4846b151d70c', 'gap', 'thresholds.vol_mult_runaway', '{"value": 1.3}', 1, 'Runaway gap volume multiplier.', false, '2026-04-23 22:43:57.36467+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('22799d6a-33cc-4c5c-81e2-d74b1c66597b', 'gap', 'thresholds.vol_mult_exhaustion', '{"value": 1.8}', 1, 'Exhaustion gap volume multiplier.', false, '2026-04-23 22:43:57.36467+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('d3e6a233-5983-4692-8384-b4035932e123', 'gap', 'thresholds.range_flat_pct', '{"value": 0.02}', 1, 'Consolidation range width cap (fraction) for breakaway classification.', false, '2026-04-23 22:43:57.36467+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('eb7a3e32-c739-46e3-8bb8-20690de4bd3f', 'classical', 'thresholds.flatness_threshold_pct', '{"value": 0.001}', 1, 'Trendline slope (fraction of price per bar) below which a line is considered "flat" for asc/desc triangle legs. Default 0.1%/bar.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('d37863c4-28ee-4b74-a1e6-1c7c3317f35c', 'classical', 'thresholds.flatness_min_score', '{"value": 0.3}', 1, 'Minimum flatness score (0..1) an asc/desc triangle needs on its flat side to qualify.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('66d705f3-ed81-4cd4-94cc-7f450f20d026', 'classical', 'thresholds.neckline_tolerance_mult', '{"value": 1.5}', 1, 'H&S neckline equality tolerance multiplier (1..3). Neckline is looser than shoulders so tolerance is equality_tolerance × this.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('cefed909-4e8a-47f2-8cd8-f80365eee613', 'classical', 'thresholds.hs_max_neckline_slope_pct', '{"value": 0.003}', 1, 'H&S neckline slope cap (fraction per bar). Above this the neckline is too steep for a valid H&S.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('e64b988d-6d43-46cf-aa8e-9750e242213d', 'classical', 'thresholds.hs_time_symmetry_tol', '{"value": 0.5}', 1, 'H&S shoulder time-symmetry tolerance (0..2). Ideal H&S has roughly equal bar-spans between LS→H and H→RS.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('1dcd2cb7-492c-494f-a5c9-14b675b4a9b9', 'classical', 'thresholds.triangle_symmetry_tol', '{"value": 0.5}', 1, 'Symmetrical triangle slope-symmetry tolerance (|upper.slope| vs lower.slope, fractional).', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('78f22d0d-107c-4811-93f7-869df4eb8b51', 'classical', 'thresholds.rectangle_max_slope_pct', '{"value": 0.002}', 1, 'Rectangle max trendline slope (fraction per bar). Beyond this the pattern is a channel or triangle, not a rectangle.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('843e3b3a-2499-4e48-9104-d59598711bb0', 'classical', 'thresholds.rectangle_min_bars', '{"value": 15}', 1, 'Minimum bar-span from first to last rectangle pivot — filters short "range" noise.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('3b548077-af8f-4735-bb2c-10c007916be3', 'classical', 'thresholds.flag_pole_min_move_atr', '{"value": 3.0}', 1, 'Flagpole minimum directional move as an ATR multiple (0..20). Default 3.0 → pole ≥ 3×ATR.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('b6252daa-0ee8-42ce-a833-25f1ccc9b6f3', 'classical', 'thresholds.flag_pole_max_bars', '{"value": 20}', 1, 'Lookback window (bars) for flagpole detection.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('410879f5-6b1e-4be9-a0a9-82d7635313e2', 'classical', 'thresholds.flag_max_retrace_pct', '{"value": 0.5}', 1, 'Flag body may retrace at most this fraction (0..1) of the flagpole height.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('558aa592-8716-4880-81d5-793f50aa3ca4', 'classical', 'thresholds.flag_atr_period', '{"value": 14}', 1, 'Wilder ATR period for flag / pennant bar-geometry checks.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('0c6bba16-cbfe-4eb9-b693-66134215c54b', 'classical', 'thresholds.flag_parallelism_tol', '{"value": 0.3}', 1, 'Flag channel slope parallelism tolerance (|upper.slope - lower.slope|/avg, 0..2).', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('f3357255-f761-4267-9797-ebb89b87a0ba', 'classical', 'thresholds.pennant_max_height_pct_of_pole', '{"value": 0.4}', 1, 'Pennant max height as a fraction (0..1) of the flagpole height.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('3991b558-d21e-4b27-a1ab-bb22e0840406', 'classical', 'thresholds.channel_parallelism_tol', '{"value": 0.15}', 1, 'Channel parallelism tolerance (|upper.slope - lower.slope|/avg).', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('30cc86cd-838c-4323-83d3-77cf175d7ceb', 'classical', 'thresholds.channel_min_bars', '{"value": 20}', 1, 'Channel minimum bar-span from first to last pivot.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('17da05b2-796e-4674-916f-1b9f057e68d7', 'classical', 'thresholds.channel_min_slope_pct', '{"value": 0.001}', 1, 'Channel minimum |slope| (fraction per bar); below this the shape is a rectangle, not a channel.', false, '2026-04-23 22:12:05.747358+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('ea5e1b74-687c-4e9c-a8c7-87541a8ec2fe', 'classical', 'thresholds.cup_min_bars', '{"value": 30}', 1, 'Cup minimum bars from rim_left to rim_right (Bulkowski: ~7 weekly bars; scaled per TF).', false, '2026-04-23 22:12:05.747358+03', NULL);
