INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('c57735f3-6edf-4e37-a310-a0b1bcb4bd9d', 'range', 'enabled', '{"enabled": true}', 1, 'Master on/off for the range-zone engine writer inside qtss-engine. Gates the RangeWriter; individual sub-detectors have their own enable flags below.', false, '2026-04-23 22:26:41.520184+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('b7800af7-47c2-49aa-a442-279883fadc7f', 'range', 'min_score', '{"score": 0.50}', 1, 'Global quality floor applied after every sub-detector. Zones below this score are dropped before persistence. 0.50 keeps mid/high-quality zones.', false, '2026-04-23 22:26:41.520184+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('643317d7-87a8-400c-aa05-a25772e29b44', 'range', 'bars_per_tick', '{"bars": 2000}', 1, 'Upper bound on recent bars loaded per symbol per tick. All four range detectors share one ATR pass over this bar slice.', false, '2026-04-23 22:26:41.520184+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('72d958b1-9875-462a-a194-371955876768', 'range', 'atr_period', '{"period": 14}', 1, 'Wilder ATR period used for zone-size / impulse / cluster thresholds. 14 matches standard technical-analysis convention.', false, '2026-04-23 22:26:41.520184+03', NULL);
