INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('a71c35e3-54f5-45cd-b276-13192cfc758d', 'range', 'fvg.scan_lookback', '{"value": 50}', 1, 'How many recent bars to scan for FVG candidates per tick.', false, '2026-04-23 22:26:41.520184+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('208a6ca2-6203-4f76-bb7d-50e5405157a2', 'range', 'fvg.unfilled_only', '{"value": true}', 1, 'When true, drop any FVG that price has already filled — only un-mitigated gaps are persisted.', false, '2026-04-23 22:26:41.520184+03', NULL);
