INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('9546a1ce-1c99-4a18-ad25-cd664aed72f2', 'indicator_persistence', 'enabled', '{"enabled": true}', 1, 'Master on/off for the indicator snapshot writer. Disable to stop writes entirely (e.g. during migration windows).', false, '2026-04-23 23:48:36.128071+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('d42cdfe2-8d50-4ba3-a050-df411876f283', 'indicator_persistence', 'tick_secs', '{"secs": 60}', 1, 'Loop cadence in seconds. One engine tick = one new bar-close persistence pass per symbol/TF.', false, '2026-04-23 23:48:36.128071+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('dcf7a270-f2b0-46be-b73d-bbf45975e08a', 'indicator_persistence', 'bars_per_tick', '{"bars": 300}', 1, 'Most recent N bars to (re)materialise per tick. Keeping this modest trims churn while still covering rolling re-computes when a prior bar''s indicator value shifts (Wilder smoothing, etc.).', false, '2026-04-23 23:48:36.128071+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('11088f94-53f9-41e1-8a71-2a68af5ddb20', 'indicator_persistence', 'names', '{"names": ["rsi", "ema", "bollinger", "macd", "atr", "supertrend", "keltner", "ichimoku", "donchian", "williams_r", "cmf", "aroon", "psar", "chandelier"]}', 1, 'Ordered list of indicator names to persist. The worker loops over this list and calls the same `compute_indicator` dispatch the /v2/indicators endpoint uses.', false, '2026-04-23 23:48:36.128071+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('0101411f-1ef1-4363-ad7a-a65af6c06d10', 'indicator_persistence', 'retention_days', '{"days": 90}', 1, 'TTL for snapshots. A daily purge job deletes rows older than this. 90 = roughly one quarter — enough for feature-window backtests, light enough on DB size.', false, '2026-04-23 23:48:36.128071+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('589906fc-561d-4838-884e-0e0770f1591d', 'orb', 'enabled', '{"enabled": true}', 1, 'Master on/off for the Opening Range Breakout engine writer.', false, '2026-04-23 23:59:02.258606+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('7491d3e1-d0a5-46ac-adef-7a3459081340', 'orb', 'bars_per_tick', '{"bars": 2000}', 1, 'Upper bound on recent bars loaded per symbol per tick.', false, '2026-04-23 23:59:02.258606+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('e8325383-b2a1-4d1d-b067-49108d0647d2', 'orb', 'or_bars', '{"value": 4}', 1, 'Number of bars that form the Opening Range after each session open. 4 on 15m = first hour. Crabel-style 30m ORs on 5m = 6.', false, '2026-04-23 23:59:02.258606+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('3e232b3c-b6c7-46d6-a115-4e0c9a9f9475', 'orb', 'confirm_lookback', '{"value": 12}', 1, 'Bars after the OR window to watch for a breakout close. 12 on 15m = 3 hours — keeps the pattern relevant to the current session.', false, '2026-04-23 23:59:02.258606+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('cf502d58-5785-41bc-b9d3-0b26260418fa', 'orb', 'breakout_atr_mult', '{"value": 0.10}', 1, 'Minimum breakout magnitude beyond OR boundary as an ATR multiple. Filters tick-by-tick noise; Crabel himself used 0 but ATR ≥ 10% separates real moves from rounding error.', false, '2026-04-23 23:59:02.258606+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('0f15063f-0a61-4402-8d82-ddc9ef6f9e06', 'orb', 'volume_spike_mult', '{"value": 1.2}', 1, 'Breakout bar volume must be ≥ this × SMA(volume, 20) to set `volume_confirmed`. The signal still fires without it, but the score drops.', false, '2026-04-23 23:59:02.258606+03', NULL);
INSERT INTO public.system_config (id, module, config_key, value, schema_version, description, is_secret, updated_at, updated_by_user_id) VALUES ('8b926d9b-5015-44fc-8489-87ddb8af9a3b', 'orb', 'enabled_sessions', '{"names": ["asia", "london", "new_york"]}', 1, 'Which session opens to track. Set to a subset (e.g. ["london","new_york"]) when a strategy should skip Asia opens on thin-liquidity days.', false, '2026-04-23 23:59:02.258606+03', NULL);
